// Mainクラスの定義
public class Main {
    // mainメソッドの定義
    public static void main(String[] args) {
        // 例外が発生する可能性がある処理
        try {
            int[] arr = {1, 2, 3};
            System.out.println(arr[5]);
        } catch (ArrayIndexOutOfBoundsException e) {
            System.out.println("配列の範囲外: " + e.getMessage());
        } catch (RuntimeException e) {
            System.out.println("実行時例外: " + e.getMessage());
        } catch (Exception e) {
            System.out.println("その他の例外: " + e.getMessage());
        }
    }
}

// Mainクラスの定義
public class Main {
    // mainメソッドの定義
    public static void main(String[] args) {
        // 例外が発生する可能性がある処理
        try {
            // 変数の宣言と初期化
            String s = "abc";
            int num = Integer.parseInt(s);
        } catch (NumberFormatException | ArithmeticException e) {
            System.out.println("数値関連の例外: " + e.getMessage());
        } catch (Exception e) {
            System.out.println("その他の例外");
        }
    }
}

