// InsufficientBalanceExceptionクラスの定義
class InsufficientBalanceException extends Exception {
    private int balance;
    private int amount;

    InsufficientBalanceException(int balance, int amount) {
        super("残高不足: 残高" + balance + "円に対して" + amount + "円の引き出し");
        this.balance = balance;
        this.amount = amount;
    }

    // getBalanceメソッドの定義
    int getBalance() { return balance; }
    // getAmountメソッドの定義
    int getAmount() { return amount; }
}

// BankAccountクラスの定義
class BankAccount {
    private int balance;

    BankAccount(int balance) { this.balance = balance; }

    void withdraw(int amount) throws InsufficientBalanceException {
        // 条件分岐
        if (amount > balance) {
            // 例外を投げる
            throw new InsufficientBalanceException(balance, amount);
        }
        balance -= amount;
        System.out.println(amount + "円引き出し。残高: " + balance + "円");
    }
}

// Mainクラスの定義
public class Main {
    public static void main(String[] args) {
        BankAccount account = new BankAccount(1000);
        // 例外が発生する可能性がある処理
        try {
            account.withdraw(500);
            account.withdraw(800);
        } catch (InsufficientBalanceException e) {
            System.out.println(e.getMessage());
        }
    }
}

