class MyResource implements AutoCloseable {
    String name;

    MyResource(String name) {
        this.name = name;
        System.out.println(name + " opened");
    }

    void use() {
        System.out.println(name + " used");
    }

    @Override
    public void close() {
        System.out.println(name + " closed");
    }
}

public class Main {
    public static void main(String[] args) {
        try (MyResource r1 = new MyResource("R1");
             MyResource r2 = new MyResource("R2")) {
            r1.use();
            r2.use();
        }
    }
}
// 出力:
// R1 opened
// R2 opened
// R1 used
// R2 used
// R2 closed  ← 宣言と逆順にクローズ
// R1 closed

// ErrorResourceクラスの定義
class ErrorResource implements AutoCloseable {
    @Override
    // closeメソッドの定義
    public void close() {
        // 例外を投げる
        throw new RuntimeException("close時のエラー");
    }
}

// Mainクラスの定義
public class Main {
    // mainメソッドの定義
    public static void main(String[] args) {
        // 例外が発生する可能性がある処理
        try (ErrorResource r = new ErrorResource()) {
            // 例外を投げる
            throw new RuntimeException("tryブロックのエラー");
        } catch (RuntimeException e) {
            System.out.println("主例外: " + e.getMessage());
            // 拡張for文（コレクションの全要素を順番に処理）
            for (Throwable s : e.getSuppressed()) {
                System.out.println("抑制: " + s.getMessage());
            }
        }
    }
}
// 出力:
// 主例外: tryブロックのエラー
// 抑制: close時のエラー

